#include <iostream>
#include <string>
#include <vector>

class Student {
private:
    std::string name;
    int id;

public:
    static int totalStudents;

    Student(const std::string& name_param, int id_param) : name(name_param), id(id_param) {
        totalStudents++;
    }

    static int getTotalStudents() {
        return totalStudents;
    }

    const std::string& getName() const { return name; }
    int getId() const { return id; }
};

int Student::totalStudents = 0;

int main() {
    std::cout << "Initial total students: " << Student::getTotalStudents() << '\n';

    Student s1("Alice Wonderland", 201);
    std::cout << "After s1: " << Student::getTotalStudents() << '\n';

    Student s2("Bob The Builder", 202);
    Student s3("Charlie Chaplin", 203);
    std::cout << "After s2, s3: " << Student::getTotalStudents() << '\n';

    std::string longName(500, 'Z');
    Student s_long_name(longName, 204);
    std::cout << "After s_long_name: " << Student::getTotalStudents() << '\n';

    {
        Student s4("David Copperfield", 205);
        std::cout << "After s4 (in scope): " << Student::getTotalStudents() << '\n';
    }

    std::cout << "After s4 out of scope: " << Student::getTotalStudents() << '\n';

    std::vector<Student> student_collection;
    student_collection.emplace_back("Eve Harrington", 206);
    student_collection.emplace_back("Frankenstein", 207);
    std::cout << "After vector additions: " << Student::getTotalStudents() << '\n';

    return 0;
}
